/// <summary>
/// Boss 8/8 (GDD 12.3.8, a confirmar) — "A Mente que Mata" (boss final
/// alternativo).
///
/// Preparação/scaffolding apenas (sem moveset implementado): liga-se a
/// BossController (vida, BossHealthBarUI, EnemyMultiPartBoss). A mecânica
/// própria, BEM COMO a condição que determina se este boss alternativo
/// substitui (ou se segue a) o boss final "normal", ficam para uma tarefa
/// futura — ver TODOs nos hooks abaixo.
///
/// Ideias a confirmar com o GDD: "alternativo" sugere uma condição de
/// activação (ex: PlayerProgress.IsHardModeActive, ou alguma escolha/percurso
/// do jogador) que decide qual dos dois bosses finais é enfrentado — essa lógica
/// de selecção pertence à cena/NpcAction que inicia o combate, não a este
/// controller (este apenas representa o combate em si, uma vez iniciado).
/// </summary>
public class Boss_AMenteQueMata : BossController
{
    protected override void Awake()
    {
        base.Awake();
        if (string.IsNullOrEmpty(bossId)) bossId = "a_mente_que_mata";
        if (string.IsNullOrEmpty(displayName)) displayName = "A Mente que Mata";
    }

    protected override void OnIntroStart()
    {
        // TODO (moveset): activar ataques iniciais / animação de despertar.
    }

    protected override void OnPhaseChanged(int defeatedParts, int aliveParts)
    {
        // TODO (moveset): trocar de fase ao destruir cada parte.
    }

    protected override void OnAllPartsDefeated()
    {
        // TODO (moveset): fase final / janela de vulnerabilidade total.
    }

    protected override void OnDefeated()
    {
        // TODO (moveset): sequência de derrota (drops, Action_SetBossDefeated
        // via NpcAction/UnityEvent, animação final / final do jogo).
    }
}
